// before (boot.ts)
handleChat(prompt, 'boot-startup', ...)
addMessage('boot-startup', { role:'assistant', content: finalText, ... })

// after (conceptual)
const autoSessionId = `auto_boot_${Date.now()}`;
handleChat(prompt, autoSessionId, ...)
addMessage(autoSessionId, { role:'assistant', content: finalText, ... })
broadcastWS({ type:'session_notification', automatedSession:{ id:autoSessionId, ... } })

// before (ChatPage.js)
wsEventBus.on('boot_greeting', ...active empty session only...)

// after
wsEventBus.on('session_notification', (msg) => {
  if (msg.automatedSession) upsertAutomatedSession(msg.automatedSession, { markUnread: true });
});

